module.render:
const color = args.color || 'var(--accent-color)';
const reverse = String(args.reverse) === 'true';
const shade = String(args.shade) !== 'false';
const textcolor = (args.textcolor && String(args.textcolor).trim()) || '#14213d';
let gapN = parseInt(args.gap, 10); const gap = (gapN >= 0 && gapN <= 24) ? gapN : 4;
let radN = parseInt(args.radius, 10); const radius = (radN >= 0 && radN <= 32) ? radN : 4;
const secs = sections.map((s) => (s || '').trim()).filter(Boolean);
const n = secs.length || 1;
let html = `\n\n<div class="mdp-mod-pyramid" style="--py-color:${color}; --py-text:${textcolor}; --py-gap:${gap}px; --py-radius:${radius}px;">`;
secs.forEach((s, i) => {
  const rank = reverse ? (n - i) : (i + 1);   // 1..n from narrow to wide
  const w = Math.round((rank / n) * 100);
  const mix = shade ? Math.round((25 + 60 * (rank / n))) : 100;  // darker as it widens
  html += `<div class="mdp-py-level" style="width:${w}%; background:color-mix(in srgb, var(--py-color) ${mix}%, white);">\n\n${s}\n\n</div>`;
});
html += `</div>\n\n`;
return html;
